// Filter: only process 'opportunity' events with a real trade result.
// n8n v2 webhook wraps the POST body under .body — handle both layouts.
const raw  = $input.first().json;
const item = raw.body || raw;

if (item.event !== 'opportunity') {
  return [];
}

const profitPct = parseFloat(item.profit_pct) || 0;
const inrDelta  = parseFloat(item.inr_delta)  || 0;

// Build the Claude request body here so the HTTP node stays simple.
const prompt = `You are monitoring an INR/USDT spread arbitrage bot on CoinSwitch (India).

Context:
- Cost structure: 1% TDS (tax deducted at source) + ~0.04% taker fee per leg
- Breakeven spread is approximately 1.08% net
- Current minimum spread threshold: ${parseFloat(item.min_spread_pct || 0.015) * 100}%
- A trade just executed: ${item.symbol} direction=${item.direction}
  Net profit: ${(profitPct * 100).toFixed(3)}%
  INR P&L this trade: ${inrDelta >= 0 ? '+' : ''}${inrDelta.toFixed(2)}

Your job: decide if the threshold should be adjusted.
Rules:
- Suggest "lower" only if profit_pct > current_threshold * 1.5 AND profit_pct > 0.02
  (meaning the bot is being too conservative — real edge exists well above the bar)
- Suggest "raise" if profit_pct < current_threshold * 1.05
  (trade barely cleared the bar — market may be thinner than expected)
- Suggest "hold" in all other cases
- Never recommend new_threshold below 0.012 (1.2%) — below cost floor
- Never recommend new_threshold above 0.05 (5%) — too restrictive

Respond ONLY with valid JSON, no extra text:
{"action": "lower"|"raise"|"hold", "new_threshold": <float>, "reason": "<one sentence>"}`;

return [{
  json: {
    event: item,
    profitPct,
    inrDelta,
    claudeRequest: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 200,
      messages: [{ role: 'user', content: prompt }]
    }
  }
}];

// Parse Claude's response and validate the action before applying it.
const claudeBody = $input.first().json;
const prev       = $('Filter and Build Prompt').first().json;

let action = 'hold';
let newThreshold = null;
let reason = 'Parse error';

try {
  const text = claudeBody.content?.[0]?.text || '';
  // Claude sometimes wraps JSON in markdown code fences — strip them.
  const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  action       = parsed.action || 'hold';
  newThreshold = parseFloat(parsed.new_threshold);
  reason       = parsed.reason || '';

  // Validate: clamp and reject nonsense values.
  if (!['lower', 'raise', 'hold'].includes(action)) action = 'hold';
  if (isNaN(newThreshold) || newThreshold < 0.012 || newThreshold > 0.05) {
    action = 'hold';
    reason = `Rejected: threshold ${newThreshold} out of allowed range [0.012, 0.05]`;
  }
} catch (e) {
  action = 'hold';
  reason = `JSON parse failed: ${e.message}`;
}

return [{
  json: {
    action,
    newThreshold,
    reason,
    event: prev.event,
    profitPct: prev.profitPct,
    inrDelta: prev.inrDelta
  }
}];

